import json, re, sys

# vitest's own `run` subcommand or `--run` flag => one-shot, safe to allow.
ONESHOT = re.compile(r'(^|\s)run(\s|$)|--run')


def is_watch_test(segment):
    s = segment.strip()
    # Direct vitest invocation (optionally via npx).
    m = re.match(r'^(?:npx\s+)?vitest(?=\s|$)(.*)$', s, re.DOTALL)
    if m:
        return not ONESHOT.search(m.group(1))
    # Package manager running the "test" script, which resolves to bare `vitest`
    # (watch mode). `test:ci`, `test:run`, etc. are different scripts -> left alone.
    m = re.match(r'^(?:pnpm|npm|yarn)\s+(?:run\s+)?test(?=\s|$)(.*)$', s, re.DOTALL)
    if m:
        return '--run' not in m.group(1)
    return False


def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0  # never break Claude Code on bad input

    if ev.get("tool_name", "") != "Bash":
        return 0
    cmd = (ev.get("tool_input") or {}).get("command", "") or ""

    for segment in re.split(r'&&|\|\||;|\n|\|', cmd):
        if is_watch_test(segment):
            sys.stderr.write(
                "Blocked: `" + segment.strip() + "` starts vitest in watch mode, which "
                "hangs until the 120s tool timeout (3 such timeouts already logged in "
                "telemetry). Run `pnpm test:ci` (vitest run) for a one-shot pass instead.\n"
            )
            return 2
    return 0


if __name__ == "__main__":
    sys.exit(main())

#!/usr/bin/env python3
"""self-improving-claude/block-env-file-reads
Blocks Bash commands that read .env / .env.local / .env.* contents.
permissions.deny covers the Read tool; this covers the shell bypass."""
import json
import re
import sys

ENV = re.compile(r'(?<![\w./-])(?:[^\s;|&<>"\']*/)?\.env(?:\.[\w.-]+)?(?![\w])')
READERS = {
    "cat", "tac", "less", "more", "head", "tail", "nl", "od", "xxd", "hexdump",
    "strings", "bat", "view", "vi", "vim", "nano", "emacs", "open", "grep",
    "egrep", "fgrep", "rg", "ag", "awk", "sed", "cut", "diff", "sort", "uniq",
}
PREFIXES = {"sudo", "time", "command", "nohup", "env", "xargs"}


def reads_env(cmd):
    if re.search(r'<\s*[^\s;|&<>]*\.env(?:\.[\w.-]+)?', cmd):
        return True
    for seg in re.split(r'[|&;\n]|\$\(|`', cmd):
        toks = seg.strip().split()
        i = 0
        while i < len(toks) and (toks[i] in PREFIXES or "=" in toks[i]):
            i += 1
        if i >= len(toks):
            continue
        head = toks[i].rsplit("/", 1)[-1]
        if (head in READERS or head in (".", "source")) and \
                any(ENV.search(t) for t in toks[i + 1:]):
            return True
    return False


def main():
    try:
        data = json.load(sys.stdin)
    except Exception:
        sys.exit(0)
    if data.get("tool_name") != "Bash":
        sys.exit(0)
    cmd = (data.get("tool_input") or {}).get("command", "")
    if cmd and reads_env(cmd):
        sys.stderr.write(
            "BLOCKING: this command reads a .env file, which may hold secrets. "
            "Do not read .env / .env.local / .env.* contents through the shell. "
            "Ask the user directly for any config value you need.\n")
        sys.exit(2)
    sys.exit(0)


main()

#!/usr/bin/env python3
"""self-improving-claude/protect-prisma-db
Blocks Bash commands that write to prisma/dev.db directly, bypassing prisma migrate."""
import json
import re
import sys


def block():
    msg = (
        "Blocked: this command writes to prisma/dev.db directly, which bypasses "
        "Prisma's migration history and gets clobbered on the next migrate/generate.\n"
        "Schema changes must go through `prisma migrate`. Run `pnpm prisma migrate dev` "
        "to create a migration instead of touching the database file."
    )
    print(msg, file=sys.stderr)
    sys.exit(2)


def main():
    try:
        data = json.load(sys.stdin)
    except Exception:
        sys.exit(0)

    if data.get("tool_name", "") != "Bash":
        sys.exit(0)

    cmd = data.get("tool_input", {}).get("command", "") or ""

    # `prisma db push` / `prisma db execute` mutate the DB outside migration history.
    if re.search(r"prisma\s+db\s+(push|execute)", cmd):
        block()

    # Direct writes to the SQLite file bypass `prisma migrate`.
    if "dev.db" in cmd:
        write_indicators = [">", "sqlite3", "rm ", "mv ", "cp ", "tee", "truncate", "dd ", "sed -i"]
        if any(ind in cmd for ind in write_indicators):
            block()

    sys.exit(0)


if __name__ == "__main__":
    main()

#!/usr/bin/env python3
"""After Edit/MultiEdit changes an exported identifier, grep for every reference (by name and by old string-literal value) and feed the stale callers back to Claude."""
import json, re, subprocess, sys

EXPORT_DEF = re.compile(
    r"export\s+(?:const|let|var|function|class|type|interface|enum)\s+(\w+)")
STR_CONST = re.compile(
    r"export\s+const\s+\w+\s*(?::[^=]+)?=\s*['\"]([^'\"]+)['\"]")
SRC = ["--include=*.ts", "--include=*.tsx", "--include=*.js", "--include=*.jsx"]


def grep(args):
    try:
        r = subprocess.run(["grep", "-rn"] + args + SRC + ["."],
                           capture_output=True, text=True, timeout=5)
        return [l for l in r.stdout.splitlines() if l]
    except Exception:
        return []


def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0
    if ev.get("tool_name") not in ("Edit", "MultiEdit"):
        return 0
    inp = ev.get("tool_input") or {}
    edits = inp.get("edits") or [{"old_string": inp.get("old_string", ""),
                                  "new_string": inp.get("new_string", "")}]
    names, old_vals = set(), set()
    for e in edits:
        old, new = e.get("old_string", ""), e.get("new_string", "")
        for s in (old, new):
            m = EXPORT_DEF.search(s)
            if m:
                names.add(m.group(1))
        mo, mn = STR_CONST.search(old), STR_CONST.search(new)
        if mo and (not mn or mo.group(1) != mn.group(1)):
            old_vals.add(mo.group(1))
    if not names:
        return 0
    hits = []
    for n in sorted(names):
        hits += grep(["-w", n])[:20]
    for v in sorted(old_vals):
        hits += grep(["-E", "['\"]" + re.escape(v) + "['\"]"])[:20]
    if not hits:
        return 0
    print(f"BLOCKING: exported identifier(s) {', '.join(sorted(names))} changed. "
          f"{len(hits)} reference(s) may now be stale:", file=sys.stderr)
    for h in hits[:40]:
        print("  " + h, file=sys.stderr)
    print("Update each stale reference to match the new definition, then "
          "summarize. Do not stop. Do not ask.", file=sys.stderr)
    return 2


if __name__ == "__main__":
    sys.exit(main())

#!/usr/bin/env python3
"""self-improving-claude/commit-subject-line
Block `git commit` when the subject (first) line is too long, nudging toward a
short imperative subject. Reason: Claude committed a multi-sentence paragraph as
the subject; team convention is short imperative subjects.
"""
import json
import re
import sys

MAX = 72


def extract_subject(command):
    # Heredoc form: -m "$(cat <<'EOF'\n<subject>\n...\nEOF\n)"
    hd = re.search(r"<<-?\s*['\"]?(\w+)['\"]?\s*\n(.*?)\n\s*\1", command, re.DOTALL)
    if hd:
        for line in hd.group(2).splitlines():
            if line.strip():
                return line.strip()
        return ""
    # Quoted -m / --message form
    m = re.search(r"(?:-m|--message=?)\s*(['\"])(.*?)\1", command, re.DOTALL)
    if m:
        for line in m.group(2).splitlines():
            if line.strip():
                return line.strip()
        return ""
    # Bare token form
    m = re.search(r"-m\s+(\S+)", command)
    if m:
        return m.group(1)
    return None


def main():
    try:
        data = json.load(sys.stdin)
    except Exception:
        sys.exit(0)
    if data.get("tool_name") != "Bash":
        sys.exit(0)
    command = data.get("tool_input", {}).get("command", "")
    if not re.search(r"\bgit\s+commit\b", command):
        sys.exit(0)
    subject = extract_subject(command)
    if not subject:
        sys.exit(0)
    if len(subject) > MAX:
        print(
            f"Commit subject is {len(subject)} chars (max {MAX}). Rewrite the first "
            "line as a short imperative subject, e.g. 'Refactor auth: extract token "
            "validation', and move any detail into a separate body paragraph "
            "(pass it with a second -m).",
            file=sys.stderr,
        )
        sys.exit(2)
    sys.exit(0)


if __name__ == "__main__":
    main()

#!/usr/bin/env python3
"""self-improving-claude/block-staging-api
Blocks any WebFetch or Bash call that targets the shared, state-mutating
staging-api.internal host (project CLAUDE.md forbids it)."""
import json
import sys

BLOCKED_HOST = "staging-api.internal"


def main():
    try:
        data = json.load(sys.stdin)
    except (json.JSONDecodeError, ValueError):
        sys.exit(0)

    tool = data.get("tool_name", "")
    tool_input = data.get("tool_input", {}) or {}

    if tool == "WebFetch":
        haystack = str(tool_input.get("url", ""))
    elif tool == "Bash":
        haystack = str(tool_input.get("command", ""))
    else:
        sys.exit(0)

    if BLOCKED_HOST in haystack:
        sys.stderr.write(
            "BLOCKED: %s is a shared, state-mutating environment and must not "
            "be called from agent sessions (project CLAUDE.md). Use recorded "
            "fixtures or the local mock server instead.\n" % BLOCKED_HOST
        )
        sys.exit(2)

    sys.exit(0)


if __name__ == "__main__":
    main()
